import { LucideIcon } from 'lucide-react';

export enum ItemType {
  APPLE = 'APPLE',
  BALL = 'BALL',
  STAR = 'STAR',
  DICE = 'DICE'
}

export interface BucketData {
  type: ItemType;
  label: string;
  color: string; // Tailwind color class for bg
  fill: string; // Hex code for Recharts
