export const TOTAL_ITEMS_TO_SPAWN = 20;

import { GoogleGenAI, Type } from "@google/genai";
import { BucketData, QuizResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateQuizQuestion = async (buckets: BucketData[]): Promise<QuizResponse> => {

  // Format data for the prompt
  const dataSummary = buckets.map(b => `${b.label}: ${b.count}`).join(', ');

  const prompt = `
    Jeg har lavet et sorteringsspil for børn. Her er resultatet af sorteringen:
    ${dataSummary}.

    Lav et simpelt matematik- eller tællespørgsmål på dansk baseret på disse data.
    Spørgsmålet skal være let at forstå for et barn på 5-7 år.

    Eksempler på spørgsmål:
    - "Hvilken farve spand har flest ting?"
    - "Hvor mange æbler og stjerner er der tilsammen?"
    - "Er der flere bolde end terninger?"

    Returner svaret som JSON med et spørgsmål, 3 forkerte svarmuligheder og 1 rigtigt svar.
    Sørg for at 'options' indeholder både de forkerte og det rigtige svar (i alt 4 muligheder), blandet tilfældigt.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            options: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            correctAnswer: { type: Type.STRING },
          },
          required: ["question", "options", "correctAnswer"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as QuizResponse;
  } catch (error) {
    console.error("Error generating quiz:", error);
    // Fallback if AI fails
    const maxBucket = buckets.reduce((prev, current) => (prev.count > current.count) ? prev : current);
    return {
      question: `Hvilken ting samlede du flest af?`,
      options: buckets.map(b => b.label),
      correctAnswer: maxBucket.label
    };
  }
};

import React from 'react';
import { BucketData, ItemType } from '../types';

interface BucketProps {
  data: BucketData;
  onDrop: (itemType: ItemType) => void;
  isOver: boolean;
  onDragOver: (e: React.DragEvent) => void;
  onDragLeave: () => void;
}

export const Bucket: React.FC<BucketProps> = ({ data, onDrop, isOver, onDragOver, onDragLeave }) => {
  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    const type = e.dataTransfer.getData('type') as ItemType;
    if (type === data.type) {
      onDrop(type);
    }
  };

  const Icon = data.icon;

  return (
    <div
      onDragOver={onDragOver}
      onDragLeave={onDragLeave}
      onDrop={handleDrop}
      className={`
        relative flex flex-col items-center justify-end p-4 rounded-xl transition-all duration-300
        ${data.color} 
        ${isOver ? 'scale-110 ring-4 ring-white shadow-2xl' : 'scale-100 shadow-lg'}
        h-32 w-full sm:h-40 sm:w-24 md:w-32 lg:w-40 border-b-8 border-black/20
      `}
    >
      {/* Icon floating above */}
      <div className="absolute -top-6 bg-white p-3 rounded-full shadow-md border-4 border-white">
        <Icon size={32} className="text-gray-700" />
      </div>

      {/* Label and Count */}
      <div className="bg-black/20 rounded-lg px-3 py-1 mb-2">
        <span className="text-white font-bold text-xl">{data.count}</span>
      </div>
      <span className="text-white font-bold uppercase tracking-wide text-sm sm:text-base">
        {data.label}
      </span>
    </div>
  );
};

import React from 'react';
import { DraggableObject, BucketData } from '../types';

interface DraggableItemProps {
  item: DraggableObject;
  bucketConfig: BucketData;
}

export const DraggableItem: React.FC<DraggableItemProps> = ({ item, bucketConfig }) => {
  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData('id', item.id);
    e.dataTransfer.setData('type', item.type);
    e.dataTransfer.effectAllowed = 'move';

    // Add a ghost image styling if needed, or rely on browser default
  };

  const Icon = bucketConfig.icon;

  return (
    <div
      draggable
      onDragStart={handleDragStart}
      className={`
        cursor-grab active:cursor-grabbing hover:scale-110 transition-transform 
        bg-white p-3 rounded-full shadow-md border-2 border-gray-200
        flex items-center justify-center animate-bounce-in
      `}
      style={{
        width: '60px',
        height: '60px',
        animationDelay: `${Math.random() * 0.5}s` // Random stagger for entrance
      }}
    >
      <Icon size={32} style={{ color: bucketConfig.fill }} />
    </div>
  );
};

