import React from 'react';
import { DraggableObject, BucketData } from '../types';

interface DraggableItemProps {
  item: DraggableObject;
  bucketConfig: BucketData;
}

export const DraggableItem: React.FC<DraggableItemProps> = ({ item, bucketConfig }) => {
  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData('id', item.id);
    e.dataTransfer.setData('type', item.type);
    e.dataTransfer.effectAllowed = 'move';
  };

  const Icon = bucketConfig.icon;

  return (
    <div
      draggable
      onDragStart={handleDragStart}
      className={`
        cursor-grab active:cursor-grabbing hover:scale-110 transition-transform 
        bg-white p-1 rounded-full shadow-sm border-2 border-gray-100
        flex items-center justify-center animate-bounce-in
      `}
      style={{
        width: '64px',
        height: '64px',
        animationDelay: `${Math.random() * 0.5}s`
      }}
    >
      {/* 
        We use the custom colorful icons, so no 'color' style is needed.
        Increased size slightly for better visibility.
      */}
      <Icon size={48} />
    </div>
  );
};

import React from 'react';
import { BucketData, ItemType } from '../types';

interface BucketProps {
  data: BucketData;
  onDrop: (itemType: ItemType) => void;
  isOver: boolean;
  onDragOver: (e: React.DragEvent) => void;
  onDragLeave: () => void;
}

export const Bucket: React.FC<BucketProps> = ({ data, onDrop, isOver, onDragOver, onDragLeave }) => {
  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    const type = e.dataTransfer.getData('type') as ItemType;
    if (type === data.type) {
      onDrop(type);
    }
  };

  const Icon = data.icon;

  return (
    <div
      onDragOver={onDragOver}
      onDragLeave={onDragLeave}
      onDrop={handleDrop}
      className={`
        relative flex flex-col items-center justify-end p-4 rounded-xl transition-all duration-300
        ${data.color} 
        ${isOver ? 'scale-105 ring-4 ring-white shadow-2xl translate-y-[-5px]' : 'scale-100 shadow-lg'}
        h-36 w-full sm:h-44 border-b-8 border-black/20
      `}
    >
      {/* Icon floating above */}
      <div className={`absolute -top-8 bg-white p-2 rounded-full shadow-lg border-4 border-white transition-transform ${isOver ? 'rotate-12 scale-110' : ''}`}>
        <Icon size={48} />
      </div>

      {/* Label and Count */}
      <div className="bg-black/20 rounded-lg px-4 py-1 mb-2 backdrop-blur-sm">
        <span className="text-white font-black text-2xl drop-shadow-md">{data.count}</span>
      </div>
      <span className="text-white font-bold uppercase tracking-wider text-sm sm:text-base drop-shadow-md">
        {data.label}
      </span>
    </div>
  );
};

