import React from 'react';
import { BucketData, ItemType } from '../types';
import { HelpCircle } from 'lucide-react';

interface BucketProps {
  data: BucketData;
  onDrop: (itemType: ItemType) => void;
  isOver: boolean;
  onDragOver: (e: React.DragEvent) => void;
  onDragLeave: () => void;
}

export const Bucket: React.FC<BucketProps> = ({ data, onDrop, isOver, onDragOver, onDragLeave }) => {
  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    const type = e.dataTransfer.getData('type') as ItemType;
    if (type === data.type) {
      onDrop(type);
    }
  };

  const Icon = data.icon;
  const isEmpty = data.count === 0;

  return (
    <div
      onDragOver={onDragOver}
      onDragLeave={onDragLeave}
      onDrop={handleDrop}
      className={`
        relative flex flex-col items-center justify-end p-4 rounded-xl transition-all duration-500
        ${isEmpty 
          ? 'bg-gray-50 border-4 border-dashed border-gray-300 shadow-inner' 
          : `${data.color} shadow-lg border-b-8 border-black/20`
        }
        ${isOver ? 'scale-105 ring-4 ring-indigo-300/50 -translate-y-1' : 'scale-100'}
        h-36 w-full sm:h-44
      `}
    >
      {/* Icon floating above */}
      <div className={`
        absolute -top-8 p-2 rounded-full transition-all duration-500
        ${isEmpty 
          ? 'bg-gray-100 border-4 border-gray-200 opacity-40 grayscale' 
          : 'bg-white shadow-lg border-4 border-white rotate-0'
        }
        ${isOver && isEmpty ? 'scale-110 opacity-70' : ''}
        ${isOver && !isEmpty ? 'scale-110 rotate-12' : ''}
      `}>
        <Icon size={48} />
      </div>

      {/* Label and Count */}
      <div className={`
        rounded-lg px-4 py-1 mb-2 backdrop-blur-sm transition-all duration-500
        ${isEmpty ? 'bg-gray-200/50' : 'bg-black/20'}
      `}>
        <span className={`
          font-black text-2xl drop-shadow-md transition-colors
          ${isEmpty ? 'text-gray-400' : 'text-white'}
        `}>
          {data.count}
        </span>
      </div>

      <span className={`
        font-bold uppercase tracking-wider text-sm sm:text-base drop-shadow-md transition-all duration-500
        ${isEmpty ? 'text-gray-400' : 'text-white'}
      `}>
        {isEmpty ? (
            <span className="flex items-center gap-1"><HelpCircle size={16}/> ?</span>
        ) : (
            data.label
        )}
      </span>
    </div>
  );
};

