import { GoogleGenAI, Type } from "@google/genai";
import { BucketData, QuizResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateQuizQuestion = async (buckets: BucketData[]): Promise<QuizResponse> => {

  // Format data for the prompt
  const dataSummary = buckets.map(b => `${b.label}: ${b.count}`).join(', ');

  const prompt = `
    Jeg har lavet et sorteringsspil for børn i indskolingen (6-9 år), hvor de kan se resultatet i et søjlediagram.
    Her er dataen fra diagrammet: ${dataSummary}.

    Din opgave er at lave et simpelt matematik-spørgsmål, som barnet skal besvare ved at kigge på diagrammet.

    VIGTIGT: Variér spørgsmålene. Vælg tilfældigt én af følgende typer:
    1. "Hvilken ting er der FLEST af?" (Find højeste søjle)
    2. "Hvilken ting er der FÆRREST af?" (Find laveste søjle, hvis den ikke er 0)
    3. "Hvor mange ting er der I ALT?" (Summen af alle ting)
    4. "Hvad er forskellen på den største og den mindste bunke?" (Variationsbredde: Max værdi minus Min værdi)

    Sproget skal være dansk og meget børnevenligt. Undgå svære ord som "variationsbredde", brug hellere "forskellen".

    Returner svaret som JSON med et spørgsmål, 3 forkerte svarmuligheder og 1 rigtigt svar.
    Sørg for at 'options' indeholder både de forkerte og det rigtige svar (i alt 4 muligheder), blandet tilfældigt.
    Hvis svaret er et tal, så sørg for at de forkerte svarmuligheder er tal der ligger tæt på.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            options: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            correctAnswer: { type: Type.STRING },
          },
          required: ["question", "options", "correctAnswer"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as QuizResponse;
  } catch (error) {
    console.error("Error generating quiz:", error);

    // --- ROBUST FALLBACK LOGIC ---
    // Calculates real math questions if AI fails

    const activeBuckets = buckets.filter(b => b.count > 0);
    // Sort by count for easy min/max access
    activeBuckets.sort((a, b) => a.count - b.count);

    const minBucket = activeBuckets[0];
    const maxBucket = activeBuckets[activeBuckets.length - 1];
    const totalCount = buckets.reduce((sum, b) => sum + b.count, 0);
    const difference = maxBucket.count - minBucket.count;

    // Helper to generate wrong number options
    const generateNumberOptions = (correct: number): string[] => {
        const opts = new Set<number>();
        opts.add(correct);
        while(opts.size < 4) {
            // Generate numbers within +/- 5 range, minimum 0
            const offset = Math.floor(Math.random() * 5) + 1;
            const sign = Math.random() > 0.5 ? 1 : -1;
            const val = Math.max(0, correct + (offset * sign));
            opts.add(val);
        }
        return Array.from(opts).sort(() => Math.random() - 0.5).map(String);
    };

    // Randomly pick a question type (0: Most, 1: Fewest, 2: Total, 3: Difference)
    // Only pick "Difference" or "Fewest" if we actually have variations
    let possibleTypes = [0, 2]; // Most and Total are always safe
    if (activeBuckets.length > 1 && minBucket.count !== maxBucket.count) {
        possibleTypes.push(1, 3); // Fewest and Difference allowed
    }

    const type = possibleTypes[Math.floor(Math.random() * possibleTypes.length)];

    switch (type) {
        case 1: // Fewest
            return {
                question: "Hvilken ting er der færrest af?",
                options: buckets.map(b => b.label),
                correctAnswer: minBucket.label
            };
        case 2: // Total
            return {
                question: "Hvor mange ting samlede du i alt?",
                options: generateNumberOptions(totalCount),
                correctAnswer: totalCount.toString()
            };
        case 3: // Difference
            return {
                question: `Hvad er forskellen på antallet af ${maxBucket.label} og ${minBucket.label}?`,
                options: generateNumberOptions(difference),
                correctAnswer: difference.toString()
            };
        case 0: // Most (Default)
        default:
            return {
                question: "Hvilken ting er der flest af?",
                options: buckets.map(b => b.label),
                correctAnswer: maxBucket.label
            };
    }
  }
};

